SELECT a.account_id AS id, a.account_name AS name, a.email AS email, r.role_name AS role, a.account_status AS account_status, a.tenant_id AS tenant_id, a.seller_id AS seller_id, a.warehouse_id AS warehouse_id, a.worker_code AS worker_code, a.last_login_at AS last_login_at, a.created_at AS created_at FROM account a INNER JOIN role r ON r.role_id = a.role_id
a.tenant_id = #{tenantId}
AND r.role_name = #{role}
AND a.account_status = #{accountStatus}
AND a.seller_id = #{sellerId}
AND a.warehouse_id = #{warehouseId}
AND ( a.account_name LIKE CONCAT('%', #{keyword}, '%') OR a.email LIKE CONCAT('%', #{keyword}, '%') OR a.worker_code LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY a.created_at DESC, a.account_id ASC

SELECT a.account_id AS id, a.tenant_id AS company_id, a.account_name AS name, a.email AS email, r.role_name AS role, t.tenant_name AS organization, a.seller_id AS seller_id, a.warehouse_id AS warehouse_id, a.worker_code AS worker_code, a.account_status AS status, a.created_at AS registered_at, a.last_login_at AS last_login_at FROM account a INNER JOIN role r ON r.role_id = a.role_id LEFT JOIN tenant t ON t.tenant_id = a.tenant_id
a.tenant_id = #{companyId}
AND r.role_name = #{role}
AND a.account_status = #{status}
AND ( a.account_name LIKE CONCAT('%', #{keyword}, '%') OR a.email LIKE CONCAT('%', #{keyword}, '%') OR a.worker_code LIKE CONCAT('%', #{keyword}, '%') OR t.tenant_name LIKE CONCAT('%', #{keyword}, '%') OR t.tenant_code LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY a.created_at DESC, a.account_id ASC
